det_check_template:
proof fn det_put<V>(self_: &PCell<V>, pre_perm: PointsTo<V>, v: V, post1_perm: PointsTo<V>, r1: (), post2_perm: PointsTo<V>, r2: ())
    requires (pre_perm@ == pcell_points![ self_.id() => MemContents::Uninit ]),
    ensures
        ({
            &&& (post1_perm@ == pcell_points![ self_.id() => MemContents::Init(v) ])
            &&& (post2_perm@ == pcell_points![ self_.id() => MemContents::Init(v) ])
        }) ==> det_put_equal::<V>(r1, r2, post1_perm, post2_perm),
{
{ASSUMES}}

equal_fn_def:
// Generated equal-fn for determinism check.
// Policy: errs_equivalent=True, opaque_ok=False
spec fn det_put_equal<V>(r1: (), r2: (), post1_perm: PointsTo<V>, post2_perm: PointsTo<V>) -> bool {
    (r1 == r2)
    && (((post1_perm).is_init() == (post2_perm).is_init()) && ((post1_perm).ptr().addr() == (post2_perm).ptr().addr()) && ((post1_perm).is_init() ==> ((post1_perm).value() == (post2_perm).value())))
}
